package com.manhmoc.edgebar; import android.content.Intent; import android.service.quicksettings.Tile; import android.service.quicksettings.TileService; public class OverlayTileService extends TileService { @Override public void onClick() { super.onClick(); try { Intent sInt = new Intent(this, HomescreenService.class); if (HomescreenService.isRunning) { stopService(sInt); Tile t = getQsTile(); if(t != null) { t.setState(Tile.STATE_INACTIVE); t.updateTile(); } } else { if (android.os.Build.VERSION.SDK_INT >= 26) startForegroundService(sInt); else startService(sInt); Tile t = getQsTile(); if(t != null) { t.setState(Tile.STATE_ACTIVE); t.updateTile(); } } } catch(Exception e){} } @Override public void onStartListening() { super.onStartListening(); try { Tile t = getQsTile(); if(t != null) { t.setState(HomescreenService.isRunning ? Tile.STATE_ACTIVE : Tile.STATE_INACTIVE); t.updateTile(); } } catch(Exception e){} } }
